use std::fmt::{self, Display};

#[derive(Debug)]
enum PointVariant {
    IntPoint { x: i32, y: i32 },
    FloatBox { min_x: f64, max_x: f64, min_y: f64, max_y: f64 },
}

impl Display for PointVariant {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            PointVariant::IntPoint { x, y } => write!(f, "Integer Point: ({}, {})", x, y),
            PointVariant::FloatBox { min_x, max_x, min_y, max_y } => write!(f, "Float Box: [{:.1}, {:.1}] x [{:.1}, {:.1}]", min_x, max_x, min_y, max_y),
        }
    }
}

fn process_coordinate(coord: PointVariant) -> String {
    match coord {
        PointVariant::IntPoint { .. } => format!("Successfully processed an integer coordinate structure."),
        PointVariant::FloatBox { .. } => format!("Successfully indexed a floating point bounding box."),
    }
}

fn main() {
    let int_coord = PointVariant::IntPoint { x: 10, y: 20 };
    let float_coord = PointVariant::FloatBox { min_x: -5.0, max_x: 5.0, min_y: 1.0, max_y: 10.0 };

    println!("Input 1: {}", int_coord);
    let result1 = process_coordinate(int_coord);
    println!("Result 1: {}
", result1);

    println!("Input 2: {}", float_coord);
    let result2 = process_coordinate(float_coord);
    println!("Result 2: {}", result2);
}
